import { randomUUID } from "node:crypto";
import { appendFileSync } from "node:fs";
import { pathToFileURL } from "node:url";

export const START_MARKER = "<!-- agent-pr-description:start -->";
export const END_MARKER = "<!-- agent-pr-description:end -->";

const ATTRIBUTION =
  "*PR description generated by [Agent](https://weekendsuperhero.io)*";

function stripMarkdownFence(value) {
  const trimmed = value.trim();
  const openingFence = /^```(?:json)?\s*\r?\n?/i;
  const closingFence = /\r?\n?```\s*$/;
  return trimmed.replace(openingFence, "").replace(closingFence, "").trim();
}

export function parseGeneratedOutput(generatedOutput, currentTitle) {
  const cleaned = stripMarkdownFence(generatedOutput);

  try {
    const parsed = JSON.parse(cleaned);
    if (
      typeof parsed.title === "string" &&
      parsed.title.trim() !== "" &&
      typeof parsed.body === "string" &&
      parsed.body.trim() !== ""
    ) {
      return {
        title: parsed.title.trim(),
        body: parsed.body.trim(),
        usedJson: true,
      };
    }
  } catch {
    // A plain Markdown response is a supported fallback.
  }

  if (generatedOutput.trim() === "") {
    throw new Error("Generated PR description is empty");
  }

  return {
    title: currentTitle,
    body: generatedOutput.trim(),
    usedJson: false,
  };
}

function markerCount(value, marker) {
  return value.split(marker).length - 1;
}

export function renderManagedSection(generatedBody) {
  const body = generatedBody.trim();
  if (body === "") {
    throw new Error("Managed PR description body is empty");
  }
  if (body.includes(START_MARKER) || body.includes(END_MARKER)) {
    throw new Error("Generated PR description contains reserved managed markers");
  }

  return `${START_MARKER}\n${body}\n\n---\n${ATTRIBUTION}\n${END_MARKER}`;
}

export function mergeManagedSection(currentBody, generatedBody) {
  const current = currentBody ?? "";
  const section = renderManagedSection(generatedBody);
  const startCount = markerCount(current, START_MARKER);
  const endCount = markerCount(current, END_MARKER);

  if (startCount === 0 && endCount === 0) {
    if (current === "") {
      return section;
    }

    const separator = current.endsWith("\n\n")
      ? ""
      : current.endsWith("\n")
        ? "\n"
        : "\n\n";
    return `${current}${separator}${section}`;
  }

  if (startCount !== 1 || endCount !== 1) {
    throw new Error(
      "PR body must contain exactly one complete Agent managed section",
    );
  }

  const startIndex = current.indexOf(START_MARKER);
  const endIndex = current.indexOf(END_MARKER, startIndex + START_MARKER.length);
  if (endIndex < startIndex) {
    throw new Error("Agent managed-section markers are out of order");
  }

  return `${current.slice(0, startIndex)}${section}${current.slice(endIndex + END_MARKER.length)}`;
}

function appendOutput(name, value) {
  const outputPath = process.env.GITHUB_OUTPUT;
  if (!outputPath) {
    throw new Error("GITHUB_OUTPUT is not set");
  }

  let delimiter = `AGENT_OUTPUT_${randomUUID()}`;
  while (value.includes(delimiter)) {
    delimiter = `AGENT_OUTPUT_${randomUUID()}`;
  }

  appendFileSync(
    outputPath,
    `${name}<<${delimiter}\n${value}\n${delimiter}\n`,
    "utf8",
  );
}

function run() {
  const currentTitle = process.env.CURRENT_TITLE ?? "";
  const currentBody = process.env.CURRENT_BODY ?? "";
  const generatedOutput = process.env.GENERATED_OUTPUT ?? "";
  const parsed = parseGeneratedOutput(generatedOutput, currentTitle);
  const body = mergeManagedSection(currentBody, parsed.body);

  if (!parsed.usedJson) {
    console.log(
      "Jules output is not valid title/body JSON; preserving the current title",
    );
  }

  appendOutput("title", parsed.title);
  appendOutput("body", body);
  appendOutput(
    "changed",
    String(parsed.title !== currentTitle || body !== currentBody),
  );
}

const invokedAsScript =
  process.argv[1] && import.meta.url === pathToFileURL(process.argv[1]).href;
if (invokedAsScript) {
  try {
    run();
  } catch (error) {
    console.error(`::error::${error instanceof Error ? error.message : error}`);
    process.exitCode = 1;
  }
}
